arguments.file_text:
export function initScrollWatcher(sentinel, dotNetRef) {
    if (!sentinel) return null;

    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnScrolledToTop');
            }
        },
        { threshold: 0.1 }
    );
    observer.observe(sentinel);
    return observer;
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function dispose(observer) {
    if (observer) {
        observer.disconnect();
    }
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="channel-header">
        <h5 class="mb-0"># @CurrentChannel?.Name</h5>
        @if (!string.IsNullOrWhiteSpace(CurrentChannel?.Description))
        {
            <span class="channel-desc">@CurrentChannel.Description</span>
        }
    </div>

    <div class="message-list" @ref="messageListRef">
        <div @ref="scrollSentinel" class="scroll-sentinel"></div>
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{CurrentChannel?.Name}")"
                  ButtonText="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference messageListRef;
    private ElementReference scrollSentinel;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private int? previousChannelId;
    private int previousMessageCount;

    private ThreadSummary? GetThreadSummary(int messageId)
        => ThreadSummaries.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-e05051409b584831a4964cdd1d25e4d8/Components/Chat/MessageArea.razor.js");
            observer = await module.InvokeAsync<IJSObjectReference>(
                "initScrollWatcher", scrollSentinel, dotNetRef);
            await ScrollToBottom();
        }

        // Scroll to bottom when switching channels or a new message is added at the end
        if (CurrentChannel?.Id != previousChannelId || Messages.Count > previousMessageCount)
        {
            previousChannelId = CurrentChannel?.Id;
            previousMessageCount = Messages.Count;
            await ScrollToBottom();
        }
    }

    private async Task ScrollToBottom()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null && observer is not null)
        {
            await module.InvokeVoidAsync("dispose", observer);
            await observer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

