arguments.file_text:
.chat-page-layout {
    height: 100vh;
    overflow: hidden;
}

@page "/chat"
@rendermode InteractiveServer
@layout ChatLayout
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelList Channels="channels"
                     SelectedChannelId="selectedChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadRootMessage is null ? "chat-main-full" : "")">
        <MessageArea CurrentChannel="selectedChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadMoreMessages"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction" />
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messageSkip = 0;
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;

        // Close any open thread when switching channels
        threadRootMessage = null;
        threadMessages = [];
        threadSummaries.Clear();

        await ChatService.MarkChannelReadAsync(channelId);

        // Clear the unread badge locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
        }

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(messageId);

        // Update the thread summary so the main message list shows "N replies"
        if (threadMessages.Count > 0)
        {
            threadSummaries[messageId] = new ThreadSummary(
                messageId,
                threadMessages.Count,
                threadMessages[^1].SentAt);
        }
    }

    private Task CloseThread()
    {
        threadRootMessage = null;
        threadMessages = [];
        return Task.CompletedTask;
    }

    private async Task SendReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannel.Id, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadMessages.Count,
            reply.SentAt);
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic local update
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
            {
                existing.Users.Add("You");
            }
        }
        else
        {
            msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background: #fff;
}

.chat-sidebar {
    width: 20%;
